const AnimatedRect = Animated.createAnimatedComponent(Rect);


export default function SplashScreenView() {
    const fillAnimation = useRef(new Animated.Value(0)).current;
    const fadeAnimation = useRef(new Animated.Value(1)).current;


    useEffect(() => {
        Animated.sequence([
        Animated.timing(fillAnimation, {
        toValue: 1,
        duration: 4000,
        useNativeDriver: false,
        }),
        Animated.timing(fadeAnimation, {
            toValue: 0,
            duration: 600,
            useNativeDriver: true,
        })
        ]).start();
    }, []);


    const xInterpolate = fillAnimation.interpolate({
        inputRange: [0, 1],
        outputRange: [-1253, 0],
    });

    return (
        <Animated.View style={[splashStyles.container, { opacity: fadeAnimation }]}>

            <Svg width={CONTENT_WIDTH} height={CONTENT_HEIGHT} viewBox={VIEWBOX}>
                <Defs>
                    <Mask id="reveal" maskUnits="userSpaceOnUse" x="0" y="0" width="1253" height="837">
                        <Path d={LOGO_PATH} fill="white" />

                        <SvgText
                            x={VB_WIDTH / 2}
                            y="721"
                            fill="white"
                            fontSize="140"
                            fontWeight="900"
                            textAnchor="middle"
                            letterSpacing="25"
                        >
                            CONNECT
                        </SvgText>
                    </Mask>
                </Defs>

                <Rect x="0" y="0" width={VB_WIDTH} height={VB_HEIGHT} fill="#E3DFD5" mask="url(#reveal)" />
                {/* <AnimatedRect y="0" width={VB_WIDTH} height={VB_HEIGHT} fill="#4AA3A2" mask="url(#reveal)" x={xInterpolate} /> */}
                <AnimatedRect
                    x="0" y="0" width={VB_WIDTH} height={VB_HEIGHT}
                    fill="#4AA3A2" mask="url(#reveal)"
                    opacity={fillAnimation}        // 0 → 1
                />
            </Svg>
         </Animated.View>
    )
}

